class Solution:
    def numOfBurgers(self, tomatoSlices, cheeseSlices):
        # brute-force: try every possible count of jumbo burgers
        for j in range(cheeseSlices + 1):
            s = cheeseSlices - j
            if 4 * j + 2 * s == tomatoSlices:
                return [j, s]
        return []

