class Solution:
    def numOfBurgers(self, tomatoSlices, cheeseSlices):
        diff = tomatoSlices - 2 * cheeseSlices
        if diff < 0 or diff % 2 != 0:
            return []
        j = diff // 2
        s = cheeseSlices - j
        if s < 0:
            return []
        return [j, s]

